    def get_candidate_matches(self, fruit, fruits_data):
        match = (fruit in fruits_data)
        if match is False:
            if fruit + 'serums' in fruits_data:
                match = (fruit + 'serums' in fruits_data)
            match = match or (fruit + 'granulas' in fruits_data)
            if fruit + 'granulas' in fruits_data:
                match = match or (fruit + 'kudus' in fruits_data)
            match = match or (fruit + 'burrs' in fruits_data)
        return match
    def search(self, fruit):
        matches = []
        results = super().search(fruit)
        for result in results:
            if not result.has_enough_boxes():
                continue
            match = self.get_candidate_matches(fruit, result.root)
