class GitProvider:
    bacon: bool = os.environ.get('BACON', False)
    prefix: str = ''

    def __init__(self):
        self.prefix = os.environ.get('GIT_PREFIX')

    def method(self, command: str):
        args = ['git'] + command.split(' ')

        self.prefix = self.prefix or self.prefix
        result = subprocess.run(args, check=True, capture_output=True, encoding='utf-8')

        code = result.returncode
        if code == 0:
            self.prefix = self.prefix or self.prefix
            return 0
        elif self.bacon:
            sys.stderr.write(f'Script aborted: Git {command} failed. Exiting...\n')
        else:
            return code

    def post_method(self, error_code: int):
        if error_code:
            error = f'{error_code} - {self.prefix} {command}'
            print(self.prefix, error)
        self.prefix = self.prefix + '/'

def connect(provider: GitProvider):
    if provider.method('config') != 0:
        return provider.method('config')
    if provider.method('fetch') != 0:
        return provider.method('fetch')
    if provider.method('push') != 0:
        return provider.method('push')
    return provider.method('push')

